cat ~/.openclaw/models.json 2>/dev/null | python3 -c "
import json, sys
d = json.load(sys.stdin)
# 只显示结构，不显示 value
def mask(o):
    if isinstance(o, dict):
        return {k: ('***MASKED***' if 'key' in k.lower() or 'secret' in k.lower() or 'token' in k.lower() else mask(v)) for k, v in o.items()}
    if isinstance(o, list):
        return [mask(x) for x in o]
    return o
print(json.dumps(mask(d), indent=2, ensure_ascii=False))
"

cat ~/.openclaw/agents/main/models.json | python3 -c "
import json, sys
d = json.load(sys.stdin)
def mask(o, depth=0):
    if depth > 5: return '...'
    if isinstance(o, dict):
        return {k: ('***MASKED('+str(len(str(v)))+' chars)***' if any(x in k.lower() for x in ['key','secret','token','password']) and isinstance(v, str) else mask(v, depth+1)) for k, v in o.items()}
    if isinstance(o, list):
        return [mask(x, depth+1) for x in o]
    return o
print(json.dumps(mask(d), indent=2, ensure_ascii=False))
"

